function increment(value: number): number {
  return value + 1;
}

function findFirst<T>(items: T[], predicate: (item: T) => boolean): T | undefined {
  for (const item of items) {
    if (predicate(item)) {
      return item;
    }
  }
  return undefined;
}

function useDebounce<T>(value: T, delay: number): T {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    const handle = setTimeout(() => {
      setDebounced(value);
    }, delay);
    return () => clearTimeout(handle);
  }, [value, delay]);

  return debounced;
}

type Action =
  | { type: 'add'; payload: { id: string; value: number } }
  | { type: 'remove'; payload: { id: string } }
  | { type: 'update'; payload: { id: string; value: number } }
  | { type: 'clear' }
  | { type: 'reset'; payload: Record<string, number> };

function reducer(state: Record<string, number>, action: Action): Record<string, number> {
  switch (action.type) {
    case 'add':
      return { ...state, [action.payload.id]: action.payload.value };
    case 'remove': {
      const { [action.payload.id]: removed, ...rest } = state;
      return rest;
    }
    case 'update':
      if (!(action.payload.id in state)) {
        return state;
      }
      return { ...state, [action.payload.id]: action.payload.value };
    case 'clear':
      return {};
    case 'reset':
      return action.payload;
    default:
      return state;
  }
}

function parseArgs(argv: string[]): { flags: Set<string>; options: Map<string, string>; positional: string[] } {
  const flags = new Set<string>();
  const options = new Map<string, string>();
  const positional: string[] = [];
  let i = 0;
  while (i < argv.length) {
    const arg = argv[i];
    if (arg.startsWith('--')) {
      const eq = arg.indexOf('=');
      if (eq !== -1) {
        options.set(arg.slice(2, eq), arg.slice(eq + 1));
      } else if (i + 1 < argv.length && !argv[i + 1].startsWith('-')) {
        options.set(arg.slice(2), argv[i + 1]);
        i += 1;
      } else {
        flags.add(arg.slice(2));
      }
    } else if (arg.startsWith('-') && arg.length > 1) {
      for (const c of arg.slice(1)) {
        flags.add(c);
      }
    } else {
      positional.push(arg);
    }
    i += 1;
  }
  return { flags, options, positional };
}

function applyDiscounts(items: Item[], rules: Rule[]): Item[] {
  const result: Item[] = [];
  for (const item of items) {
    let finalPrice = item.price;
    let applied = false;
    for (const rule of rules) {
      if (rule.category && rule.category !== item.category) {
        continue;
      }
      if (rule.minQuantity && item.quantity < rule.minQuantity) {
        continue;
      }
      if (rule.maxQuantity && item.quantity > rule.maxQuantity) {
        continue;
      }
      if (rule.type === 'percent') {
        finalPrice = finalPrice * (1 - rule.value / 100);
      } else if (rule.type === 'fixed') {
        finalPrice = Math.max(0, finalPrice - rule.value);
      } else if (rule.type === 'bogo') {
        if (item.quantity >= 2) {
          finalPrice = finalPrice * (Math.ceil(item.quantity / 2) / item.quantity);
        }
      }
      applied = true;
      if (rule.exclusive) {
        break;
      }
    }
    result.push({ ...item, price: finalPrice, discountApplied: applied });
  }
  return result;
}

function checkSchema(value: any, schema: any, path: string = ''): string[] {
  const errors: string[] = [];
  if (schema.type === 'object') {
    if (typeof value !== 'object' || value === null || Array.isArray(value)) {
      errors.push(`${path}: expected object`);
      return errors;
    }
    if (schema.required) {
      for (const key of schema.required) {
        if (!(key in value)) {
          errors.push(`${path}.${key}: missing required field`);
        }
      }
    }
    if (schema.properties) {
      for (const key of Object.keys(value)) {
        if (schema.properties[key]) {
          const childErrors = checkSchema(value[key], schema.properties[key], `${path}.${key}`);
          for (const e of childErrors) {
            errors.push(e);
          }
        } else if (schema.additionalProperties === false) {
          errors.push(`${path}.${key}: unexpected property`);
        }
      }
    }
  } else if (schema.type === 'array') {
    if (!Array.isArray(value)) {
      errors.push(`${path}: expected array`);
      return errors;
    }
    if (schema.items) {
      for (let i = 0; i < value.length; i++) {
        const childErrors = checkSchema(value[i], schema.items, `${path}[${i}]`);
        for (const e of childErrors) {
          errors.push(e);
        }
      }
    }
    if (schema.minItems && value.length < schema.minItems) {
      errors.push(`${path}: too few items`);
    }
  } else if (schema.type === 'string') {
    if (typeof value !== 'string') {
      errors.push(`${path}: expected string`);
    } else if (schema.pattern && !new RegExp(schema.pattern).test(value)) {
      errors.push(`${path}: does not match pattern`);
    }
  }
  return errors;
}

function layoutFlex(container: Box, children: Box[], direction: 'row' | 'column'): void {
  const isRow = direction === 'row';
  const mainAxis = isRow ? 'width' : 'height';
  const crossAxis = isRow ? 'height' : 'width';
  const mainStart = isRow ? 'x' : 'y';
  const crossStart = isRow ? 'y' : 'x';

  let totalFlex = 0;
  let usedSpace = 0;
  for (const child of children) {
    if (child.flex && child.flex > 0) {
      totalFlex += child.flex;
    } else {
      usedSpace += child[mainAxis] || 0;
    }
    if (child.margin) {
      usedSpace += (child.margin[mainStart] || 0) * 2;
    }
  }

  const free = Math.max(0, container[mainAxis] - usedSpace);
  const flexUnit = totalFlex > 0 ? free / totalFlex : 0;
  let cursor = container[mainStart];

  for (const child of children) {
    if (child.margin) {
      cursor += child.margin[mainStart] || 0;
    }
    child[mainStart] = cursor;
    if (child.flex && child.flex > 0) {
      child[mainAxis] = flexUnit * child.flex;
    }
    if (child.alignSelf === 'stretch' || (!child.alignSelf && container.alignItems === 'stretch')) {
      child[crossAxis] = container[crossAxis];
      child[crossStart] = container[crossStart];
    } else if (child.alignSelf === 'center' || container.alignItems === 'center') {
      child[crossStart] = container[crossStart] + (container[crossAxis] - (child[crossAxis] || 0)) / 2;
    } else {
      child[crossStart] = container[crossStart];
    }
    cursor += child[mainAxis] || 0;
    if (child.margin) {
      cursor += child.margin[mainStart] || 0;
    }
  }
}

function f(a: any, b: any, c: any, d: any, e: any, g: any): any {
  let r: any = {};
  if (a) {
    for (let i = 0; i < b.length; i++) {
      const x = b[i];
      if (x.t === 'a') {
        if (c[x.k]) {
          for (let j = 0; j < d.length; j++) {
            const y = d[j];
            if (y.k === x.k) {
              if (y.v > e) {
                if (g[x.k]) {
                  r[x.k] = (r[x.k] || 0) + y.v * g[x.k];
                } else {
                  r[x.k] = (r[x.k] || 0) + y.v;
                }
              } else if (y.v < -e) {
                if (g[x.k]) {
                  r[x.k] = (r[x.k] || 0) - y.v * g[x.k];
                }
              }
            }
          }
        }
      } else if (x.t === 'b') {
        for (let k = 0; k < c[x.k]?.length || 0; k++) {
          const z = c[x.k][k];
          if (z > e || z < -e) {
            if (typeof r[x.k] === 'number') {
              r[x.k] += z;
            } else {
              r[x.k] = z;
            }
          }
        }
      } else if (x.t === 'c') {
        if (d.some((y: any) => y.k === x.k)) {
          const m = d.find((y: any) => y.k === x.k);
          if (m && m.v) {
            for (const p of Object.keys(c)) {
              if (c[p] === m.v) {
                r[p] = (r[p] || 0) + 1;
              }
            }
          }
        }
      }
    }
  }
  return r;
}

function processEvent(state: any, event: any, ctx: any): any {
  const next = { ...state };
  if (event.type === 'pointer') {
    if (event.action === 'down') {
      if (ctx.tool === 'select') {
        if (event.shift) {
          if (next.selected.includes(event.target)) {
            next.selected = next.selected.filter((id: string) => id !== event.target);
          } else {
            next.selected = [...next.selected, event.target];
          }
        } else {
          next.selected = [event.target];
        }
        next.dragging = { id: event.target, start: { x: event.x, y: event.y } };
      } else if (ctx.tool === 'pen') {
        if (!next.currentStroke) {
          next.currentStroke = { points: [{ x: event.x, y: event.y }], color: ctx.color };
        }
      } else if (ctx.tool === 'eraser') {
        for (const id of Object.keys(state.elements)) {
          if (hitTest(state.elements[id], event.x, event.y)) {
            delete next.elements[id];
          }
        }
      }
    } else if (event.action === 'move') {
      if (next.dragging) {
        const dx = event.x - next.dragging.start.x;
        const dy = event.y - next.dragging.start.y;
        for (const id of next.selected) {
          if (next.elements[id]) {
            next.elements[id] = {
              ...next.elements[id],
              x: next.elements[id].x + dx,
              y: next.elements[id].y + dy,
            };
          }
        }
        next.dragging.start = { x: event.x, y: event.y };
      } else if (next.currentStroke) {
        next.currentStroke.points.push({ x: event.x, y: event.y });
      }
    } else if (event.action === 'up') {
      if (next.dragging) {
        next.dragging = null;
      } else if (next.currentStroke) {
        const id = `stroke_${Date.now()}`;
        next.elements[id] = next.currentStroke;
        next.currentStroke = null;
      }
    }
  } else if (event.type === 'key') {
    if (event.key === 'Escape') {
      next.selected = [];
      next.dragging = null;
      next.currentStroke = null;
    }
  }
  return next;
}

type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'square'; side: number }
  | { kind: 'rectangle'; width: number; height: number }
  | { kind: 'triangle'; base: number; height: number };

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle':
      return Math.PI * shape.radius * shape.radius;
    case 'square':
      return shape.side * shape.side;
    case 'rectangle':
      return shape.width * shape.height;
    case 'triangle':
      return (shape.base * shape.height) / 2;
  }
}

async function fetchWithFallback<T>(
  primary: () => Promise<T>,
  fallback: () => Promise<T>,
  validator: (value: T) => boolean,
  timeout: number = 5000,
): Promise<T> {
  const timeoutPromise = new Promise<never>((_, reject) =>
    setTimeout(() => reject(new Error('timeout')), timeout),
  );
  try {
    const result = await Promise.race([primary(), timeoutPromise]);
    if (validator(result)) {
      return result;
    }
    throw new Error('primary result failed validation');
  } catch (primaryError) {
    try {
      const fallbackResult = await Promise.race([fallback(), timeoutPromise]);
      if (validator(fallbackResult)) {
        return fallbackResult;
      }
      throw new Error('fallback result failed validation');
    } catch (fallbackError) {
      throw new Error(`both failed: ${primaryError}, ${fallbackError}`);
    }
  }
}

function buildPaginationData(
  totalItems: number,
  currentPage: number,
  itemsPerPage: number,
): { pages: number[]; hasNext: boolean; hasPrev: boolean; offset: number } {
  // Étape 1 : calculer le nombre total de pages
  const totalPages = Math.max(1, Math.ceil(totalItems / itemsPerPage));

  // Étape 2 : borner la page courante dans [1, totalPages]
  const safePage = Math.max(1, Math.min(currentPage, totalPages));

  // Étape 3 : décider de la fenêtre de pages à afficher (max 7)
  const windowSize = 7;
  const halfWindow = Math.floor(windowSize / 2);
  let start = Math.max(1, safePage - halfWindow);
  let end = Math.min(totalPages, start + windowSize - 1);
  start = Math.max(1, end - windowSize + 1);

  // Étape 4 : générer le tableau de pages
  const pages: number[] = [];
  for (let i = start; i <= end; i++) {
    pages.push(i);
  }

  return {
    pages,
    hasNext: safePage < totalPages,
    hasPrev: safePage > 1,
    offset: (safePage - 1) * itemsPerPage,
  };
}

type State = {
  items: Record<string, { qty: number; tags: string[]; meta: Record<string, any> }>;
  history: Array<{ action: string; ts: number; payload: any }>;
};

type Action =
  | { type: 'add'; id: string; qty: number; tags?: string[] }
  | { type: 'remove'; id: string; qty?: number }
  | { type: 'tag'; id: string; tag: string }
  | { type: 'untag'; id: string; tag: string }
  | { type: 'meta'; id: string; key: string; value: any };

function reducer(state: State, action: Action): State {
  const ts = Date.now();
  const newHistory = [...state.history, { action: action.type, ts, payload: action }];
  if (action.type === 'add') {
    const existing = state.items[action.id];
    if (existing) {
      const newQty = existing.qty + action.qty;
      const newTags = action.tags ? [...new Set([...existing.tags, ...action.tags])] : existing.tags;
      return {
        items: { ...state.items, [action.id]: { ...existing, qty: newQty, tags: newTags } },
        history: newHistory,
      };
    }
    return {
      items: { ...state.items, [action.id]: { qty: action.qty, tags: action.tags || [], meta: {} } },
      history: newHistory,
    };
  } else if (action.type === 'remove') {
    const existing = state.items[action.id];
    if (!existing) return state;
    const toRemove = action.qty ?? existing.qty;
    if (toRemove >= existing.qty) {
      const { [action.id]: _, ...rest } = state.items;
      return { items: rest, history: newHistory };
    }
    return {
      items: { ...state.items, [action.id]: { ...existing, qty: existing.qty - toRemove } },
      history: newHistory,
    };
  } else if (action.type === 'tag') {
    const existing = state.items[action.id];
    if (!existing || existing.tags.includes(action.tag)) return state;
    return {
      items: { ...state.items, [action.id]: { ...existing, tags: [...existing.tags, action.tag] } },
      history: newHistory,
    };
  } else if (action.type === 'untag') {
    const existing = state.items[action.id];
    if (!existing) return state;
    return {
      items: { ...state.items, [action.id]: { ...existing, tags: existing.tags.filter(t => t !== action.tag) } },
      history: newHistory,
    };
  } else if (action.type === 'meta') {
    const existing = state.items[action.id];
    if (!existing) return state;
    return {
      items: { ...state.items, [action.id]: { ...existing, meta: { ...existing.meta, [action.key]: action.value } } },
      history: newHistory,
    };
  }
  return state;
}

type Listener<T> = (value: T, previous: T | undefined) => void;
type Unsubscribe = () => void;

interface Observable<T> {
  get(): T;
  set(value: T): void;
  subscribe(listener: Listener<T>): Unsubscribe;
}

function createObservable<T>(initial: T): Observable<T> {
  let value = initial;
  let previous: T | undefined = undefined;
  const listeners = new Set<Listener<T>>();

  return {
    get: () => value,
    set: (newValue: T) => {
      if (newValue === value) return;
      previous = value;
      value = newValue;
      for (const listener of listeners) {
        try {
          listener(value, previous);
        } catch (e) {
          console.error('observer error', e);
        }
      }
    },
    subscribe: (listener: Listener<T>) => {
      listeners.add(listener);
      return () => {
        listeners.delete(listener);
      };
    },
  };
}
